%[text] # 例2.7（複素画素の絶対値）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example2_07"; % mfilename

imgname = "msipimg07";
imgfmt = "tiff";
%%
%[text] ## 複素画像データの生成
imgfile = fullfile(datfolder,imgname);
A = imresize(rgb2gray(im2double(imread(imgfile,imgfmt))),[96 96],'bilinear');
phi = 2*pi*rand(size(A));
X = A .* exp(1i*phi);

%%
%[text] ## 複素画像の表示
figure(1) %[output:6aaed0cf]
H = phi/(2*pi);
S = ones(size(A));
V = A;
J = hsv2rgb(cat(3,H,S,V));
imshow(J)  %[output:6aaed0cf]
title('複素画像')  %[output:6aaed0cf]

imwrite(J,fullfile(resfolder,myfilename + "a.png"))

%%
%[text] ## 絶対値複素画像の表示
Xre = real(X);
Xim = imag(X);
figure(2) %[output:482c115e]
Y = sqrt(Xre.^2 + Xim.^2);
figure(2)
imshow(Y) %[output:482c115e]
title('絶対値画像')  %[output:482c115e]
%%
%[text] ## 結果出力
imwrite(Y,fullfile(resfolder,myfilename + "b.png"))

